UPDATE c_user
SET auth_level = GREATEST(auth_level, #{authLevel}),
    update_time = CURRENT_TIMESTAMP
WHERE uid = #{uid}
  AND account_id = #{accountId}

mapper.select:
SELECT permission_key
FROM sys_role_permission
WHERE role_id = #{roleId}

SELECT EXISTS (
    SELECT 1
    FROM t_tenant_community community
    JOIN (

    ) scoped ON scoped.tenant_id = community.tenant_id
    WHERE community.status = 'ACTIVE'
      AND community.tenant_id = #{tenantId}
)
